201	// ── Pure state transition functions ────────────────────────────────────
202	
203	export function syncServerReadModel(state: AppState, readModel: OrchestrationReadModel): AppState {
204	  const projects = mapProjectsFromReadModel(
205	    readModel.projects.filter((project) => project.deletedAt === null),
206	    state.projects,
207	  );
208	  const existingThreadById = new Map(state.threads.map((thread) => [thread.id, thread] as const));
209	  const threads = readModel.threads
210	    .filter((thread) => thread.deletedAt === null)
211	    .map((thread) => {
212	      const existing = existingThreadById.get(thread.id);
213	      return {
214	        id: thread.id,
215	        codexThreadId: null,
216	        projectId: thread.projectId,
217	        title: thread.title,
218	        model: resolveModelSlugForProvider(
219	          inferProviderForThreadModel({
220	            model: thread.model,
221	            sessionProviderName: thread.session?.providerName ?? null,
222	          }),
223	          thread.model,
224	        ),
225	        runtimeMode: thread.runtimeMode,
226	        interactionMode: thread.interactionMode,
227	        session: thread.session
228	          ? {
229	              provider: toLegacyProvider(thread.session.providerName),
230	              status: toLegacySessionStatus(thread.session.status),
231	              orchestrationStatus: thread.session.status,
232	              activeTurnId: thread.session.activeTurnId ?? undefined,
233	              createdAt: thread.session.updatedAt,
234	              updatedAt: thread.session.updatedAt,
235	              ...(thread.session.lastError ? { lastError: thread.session.lastError } : {}),
236	            }
237	          : null,
238	        messages: thread.messages.map((message) => {
239	          const attachments = message.attachments?.map((attachment) => ({
240	            type: "image" as const,
241	            id: attachment.id,
242	            name: attachment.name,
243	            mimeType: attachment.mimeType,
244	            sizeBytes: attachment.sizeBytes,
245	            previewUrl: toAttachmentPreviewUrl(attachmentPreviewRoutePath(attachment.id)),
246	          }));
247	          const normalizedMessage: ChatMessage = {
248	            id: message.id,
249	            role: message.role,
250	            text: message.text,
251	            createdAt: message.createdAt,
252	            streaming: message.streaming,
253	            ...(message.streaming ? {} : { completedAt: message.updatedAt }),
254	            ...(attachments && attachments.length > 0 ? { attachments } : {}),
255	          };
256	          return normalizedMessage;
257	        }),
258	        proposedPlans: thread.proposedPlans.map((proposedPlan) => ({
259	          id: proposedPlan.id,
260	          turnId: proposedPlan.turnId,
261	          planMarkdown: proposedPlan.planMarkdown,
262	          createdAt: proposedPlan.createdAt,
263	          updatedAt: proposedPlan.updatedAt,
264	        })),
265	        error: thread.session?.lastError ?? null,
266	        createdAt: thread.createdAt,
267	        latestTurn: thread.latestTurn,
268	        lastVisitedAt: existing?.lastVisitedAt ?? thread.updatedAt,
269	        branch: thread.branch,
270	        worktreePath: thread.worktreePath,
271	        turnDiffSummaries: thread.checkpoints.map((checkpoint) => ({
272	          turnId: checkpoint.turnId,
273	          completedAt: checkpoint.completedAt,
274	          status: checkpoint.status,
275	          assistantMessageId: checkpoint.assistantMessageId ?? undefined,
276	          checkpointTurnCount: checkpoint.checkpointTurnCount,
277	          checkpointRef: checkpoint.checkpointRef,
278	          files: checkpoint.files.map((file) => ({ ...file })),
279	        })),
280	        activities: thread.activities.map((activity) => ({ ...activity })),
281	      };
282	    });
283	  return {
284	    ...state,
285	    projects,
286	    threads,
287	    threadsHydrated: true,
288	  };
289	}
