     /* …existing vars… */
     --theme-font-family: "DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
     --theme-font-size: 14px;
   }
   ```

2. Update the `body` rule to consume those variables:

   ```css
   body {
     font-family: var(--theme-font-family);
     font-size: var(--theme-font-size);
     /* …rest unchanged… */
   }
   ```

No other CSS changes are needed. The `--background`/`--foreground`/`--primary`/`--ring` variables
set inline by the hook override the `:root` declarations (inline styles have higher specificity).

---

## Step 5 — `apps/web/src/components/ThemeSelector.tsx` (new file)

A self-contained component (no props needed) that reads from `useTheme()` and renders a
radio-group of theme options with color swatches. Follows the visual language already used in
`_chat.settings.tsx`.

```tsx
import { useTheme } from "~/hooks/useTheme";

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            {/* Color swatch: background fill + sidebar strip + accent strip */}
            <div
              className="flex h-8 w-12 shrink-0 overflow-hidden rounded border border-black/10"
              aria-hidden="true"
            >
              <div className="flex-1" style={{ background: t.colors.background }} />
              <div className="w-2" style={{ background: t.colors.sidebar }} />
              <div className="w-2" style={{ background: t.colors.accent }} />
            </div>

            <span className="flex-1 text-sm font-medium">{t.name}</span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}
```

---

## Step 6 — `apps/web/src/routes/_chat.settings.tsx`

Two targeted edits:

1. **Remove** the `THEME_OPTIONS` const array and `resolvedTheme` destructure.
