import { useCallback, useSyncExternalStore } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";

/** Migrate legacy values ("dark" | "light" | "system") to new theme IDs. */
function migrateStoredId(raw: string | null): string {
  if (!raw) return DEFAULT_THEME_ID;
  if (raw === "dark" || raw === "system") return "t3-dark";
  if (raw === "light") return "t3-light";
  // Validate that stored ID exists; fall back to default
  const known = listThemes().find((t) => t.id === raw);
  return known ? raw : DEFAULT_THEME_ID;
}

function getStoredId(): string {
  return migrateStoredId(localStorage.getItem(STORAGE_KEY));
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class so existing Tailwind dark: variants keep working
  document.documentElement.classList.toggle("dark", theme.isDark);

  // Apply CSS custom properties for new theme-specific surfaces
  const style = document.documentElement.style;
  style.setProperty("--theme-background", theme.colors.background);
  style.setProperty("--theme-foreground", theme.colors.foreground);
  style.setProperty("--theme-accent", theme.colors.accent);
  style.setProperty("--theme-sidebar", theme.colors.sidebar);
  style.setProperty("--theme-editor", theme.colors.editor);
  style.setProperty("--theme-terminal", theme.colors.terminal);
  style.setProperty("--theme-status-bar", theme.colors.statusBar);
  style.setProperty("--theme-font-family", theme.fontFamily);
  style.setProperty("--theme-font-size", `${theme.fontSize.toString()}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getTheme(getStoredId()));

// ---------------------------------------------------------------------------
// External store (module-level singleton)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let cachedId: string | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSnapshot(): string {
  const id = getStoredId();
  if (cachedId === id) return cachedId;
  cachedId = id;
  return cachedId;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getTheme(getStoredId()), true);
      cachedId = null;
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId);

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next, true);
    cachedId = null;
    emitChange();
  }, []);

  const availableThemes: Theme[] = listThemes();

  return { theme, setTheme, availableThemes } as const;
}

