import { type Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ colors }: { colors: Theme["colors"] }) {
  return (
    <span className="flex shrink-0 gap-0.5 rounded-md overflow-hidden border border-black/10 dark:border-white/10" aria-hidden="true">
      <span className="h-4 w-3" style={{ background: colors.background }} />
      <span className="h-4 w-3" style={{ background: colors.sidebar }} />
      <span className="h-4 w-3" style={{ background: colors.accent }} />
      <span className="h-4 w-3" style={{ background: colors.foreground }} />
    </span>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme selection">
      {availableThemes.map((option) => {
        const selected = theme.id === option.id;
        return (
          <button
            key={option.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(option.id)}
          >
            <span className="flex min-w-0 flex-1 items-center gap-3">
              <ThemeSwatch colors={option.colors} />
              <span className="flex flex-col min-w-0">
                <span className="text-sm font-medium leading-tight">{option.name}</span>
                <span className="text-xs text-muted-foreground">
                  {option.isDark ? "Dark" : "Light"} theme
                </span>
              </span>
            </span>
            {selected ? (
              <span className="ml-3 shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

